# -*- coding: utf-8 -*-
"""Tarea 3: Resolucion de Sudoku por backtracking."""

import numpy as np


def leer_matriz(archivo):
    f = open(archivo, "r")
    M = np.zeros((9, 9), dtype=int)
    for i in range(0, 9):
        linea = f.readline()
        b = linea.split()
        for j in range(0, 9):
            M[i, j] = int(b[j])
    return M


def _en_fila(M, fila, valor):
    """Revisa si `valor` ya aparece en la fila `fila` de M."""
    for j in range(9):
        if M[fila, j] == valor:
            return True
    return False


def _en_columna(M, columna, valor):
    """Revisa si `valor` ya aparece en la columna `columna` de M."""
    for i in range(9):
        if M[i, columna] == valor:
            return True
    return False


def _en_caja(M, fila, columna, valor):
    """Revisa si `valor` ya aparece en la caja 3x3 que contiene (fila, columna)."""
    caja_fila = (fila // 3) * 3
    caja_col = (columna // 3) * 3
    for i in range(caja_fila, caja_fila + 3):
        for j in range(caja_col, caja_col + 3):
            if M[i, j] == valor:
                return True
    return False


def _es_valido(M, fila, columna, valor):
    """Verifica si `valor` puede colocarse en (fila, columna) sin repetir
    en su fila, columna o caja 3x3."""
    if _en_fila(M, fila, valor):
        return False
    if _en_columna(M, columna, valor):
        return False
    if _en_caja(M, fila, columna, valor):
        return False
    return True


def _buscar_vacia(M):
    """Encuentra la siguiente casilla con un 0. Retorna (fila, columna)
    o None si no quedan casillas vacias."""
    for i in range(9):
        for j in range(9):
            if M[i, j] == 0:
                return (i, j)
    return None


def _backtrack(M):
    """Intenta resolver el sudoku modificando M en-place.
    Retorna True si encontro solucion, False en caso contrario."""
    vacia = _buscar_vacia(M)
    if vacia is None:
        # No quedan casillas vacias: el sudoku esta resuelto.
        return True

    fila, columna = vacia
    for valor in range(1, 10):
        if _es_valido(M, fila, columna, valor):
            # Hacemos una copia para poder retroceder si la rama no funciona.
            respaldo = M.copy()
            M[fila, columna] = valor
            if _backtrack(M):
                return True
            # Backtracking: restauramos el estado anterior y probamos otro valor.
            for i in range(9):
                for j in range(9):
                    M[i, j] = respaldo[i, j]
    return False


def pruebaSudoku(M):
    """Completa el sudoku M en-place usando backtracking."""
    _backtrack(M)


if __name__ == "__main__":
    for i in range(1, 8):
        sinSolucion = "data/sudoku" + str(i) + ".txt"
        conSolucion = "data/solsudoku" + str(i) + ".txt"
        A = leer_matriz(sinSolucion)
        print("Probando solucion para " + sinSolucion + ":")
        print(A)
        B = leer_matriz(conSolucion)
        print(" ")
        print("La solucion correcta es:")
        print(B)
        print(" ")
        pruebaSudoku(A)
        print(A == B)
        print(" ")
        assert np.array_equal(A, B)
    print("Su funcion paso todos los tests")
